var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"쯧. 오늘 스파링도 엉망이야.","JPN":"チッ。今日のスパーリングもダメだな。","ENG":"Tch. Today's sparring was a mess. Again.","TWN":"嘖，今天陪練的狀態也糟呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"생각할수록 화나네. 그런 기초적인 조르기에 뻗어 놓고 칭찬을 늘어놔?","JPN":"考えれば考えるほど腹が立つ。あんな初歩的な絞め程度でやられたと褒めるなんて。","ENG":"Can't believe it. How dare he compliment me when he's the one who fainted to a basic chokehold?","TWN":"真是越想越生氣，他竟然會輸給那種基本的技巧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내 기술이 아니라 시니어 직함에 못 당해낸다는 거겠지.","JPN":"私の技がどうというより、シニアという肩書きに敵わないってことじゃないか。","ENG":"He didn't fight back because of my title as Senior, not my skills.","TWN":"根本不是我厲害，是我Senior的頭銜厲害吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"무슨 일이야?","JPN":"どうした？","ENG":"Yes?","TWN":"什麼事？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"휴무 중에 죄송합니다, 시니어님.","JPN":"お休み中、申し訳ございません。シニア。","ENG":"Apologies for contacting you on your day off, Ms. Senior.","TWN":"很抱歉打擾您休息，Senior。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"챔버에서 보낸 연구진이 체류 기간을 연장해 달라고 요청했습니다. ","JPN":"チェンバーから派遣されている研究陣から、滞在期間を延長してほしいとの要請がありました。 ","ENG":"The researchers from Chamber are requesting an extension on their stay.","TWN":"強巴派來的研究團隊請求延長停留時間。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"체류 일정을? 어째서?","JPN":"滞在期間を？　どうして？","ENG":"An extension? Why's that?","TWN":"延長停留時間？為什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"압류한 장비들을 더 분석하고 싶다더군요. ","JPN":"差し押さえた装備をもっと分析したいそうです。 ","ENG":"They said they wanted to further analyze the equipment they confiscated.","TWN":"他們說還想深入分析一下扣押的裝備。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"저희 측 연구진을 배제하고 매달렸는데도 별다른 성과가 없어서 곤란한 모양입니다.","JPN":"こちらの研究陣を排除して取り掛かったにも関わらず、あまり成果が上がらず、研究が難航しているようです。","ENG":"It seems that they have nothing to show for even when they refused the help of our researchers.","TWN":"他們堅持不讓我們的研究團隊參與，可是卻沒能取得什麼特別的成果，因此陷入膠著。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥. 온실에서 자란 것들이 다 그렇지.","JPN":"フン。温室育ちはそんなものだ。","ENG":"Hmph. That's what they get for living in a bubble for all this time.","TWN":"哼，溫室裡長大的花朵都一個德行。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"인재들이랍시고 너무 오냐오냐 키웠어, 잭슨도.","JPN":"ジャクソンも、役に立つからって甘やかしすぎたんだ。","ENG":"Guess Jackson pampered them too much.","TWN":"還說是人才，傑森是不是太看得起他們啦？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그럼 요청은 거절하시겠습니까?","JPN":"それでは、要請は拒絶しますか？","ENG":"Are you going to deny their request, ma'am?","TWN":"那要拒絕他們的請求嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아니. 체류 기간은 연장시켜 줘.","JPN":"いいや。滞在期間は延長してやれ。","ENG":"No. Give them their extension.","TWN":"不，延長他們的停留時間。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"단, 연구 지휘는 내가 직접 한다. 이만하면 잭슨의 체면은 충분히 살려 줬어.","JPN":"ただし、研究は私が直接指揮する。ジャクソンの面子はもう十分に立ててやったからな。","ENG":"However, tell them that I will lead the research from now on. I've done enough to save Jackson's face.","TWN":"不過研究工作由我親自指揮，這樣應該已經夠給傑森面子了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"네. 그러면 연구진에게는 말씀하신 대로 전달하겠습니다.","JPN":"はい。それでは、研究陣にはお言葉どおり伝えておきます。","ENG":"Understood. Then I will let the researchers know.","TWN":"是，我會把您的話轉達給研究團隊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아. 잠깐.","JPN":"あ。待て。","ENG":"Oh, wait.","TWN":"欸，等等。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자는 어떻게 됐지?","JPN":"最高管理者はどうなった？","ENG":"What happened to the Supreme Administrator?","TWN":"最高管理者現在情況如何？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"코핀 컴퍼니 샤레이드 지부로 이동했습니다.","JPN":"コフィンカンパニーのシャレード支部へと移動しました。","ENG":"He was seen going to Coffin Company's Charade branch.","TWN":"他現在正在科芬公司的查雷德分公司。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"샤레이드 시니어님과의 대담이 이루어지기 전까지는 그 곳에 머무실 듯합니다.","JPN":"シャレードのシニアとの対談が成立するまでは、そこに滞在されるかと。","ENG":"I believe he will stay there until he has a talk with Charade's Senior.","TWN":"在和查雷德Senior見面之前，似乎都會待在那裡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래. 누구와 접촉하는지 확실하게 감시해.","JPN":"そうか。誰と接触するのか、確実に監視しろ。","ENG":"Okay. Keep an eye on him and see who he comes into contact with.","TWN":"嗯，好好注意他都和誰接觸。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"예. 지시하신 대로 샤레이드에 할당된 전략 위성 중 하나도 양도 받았습니다.","JPN":"はい。ご指示どおり、シャレードに割り当てられた戦略衛星の一つも譲り受けました。","ENG":"Will do. And as you ordered, we received one of the strategic satellites assigned to Charade.","TWN":"是，已經按照您的指示，接手分配給查雷德的一顆戰略衛星。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"특이 사항이 나타나면 곧바로 보고드리겠습니다.","JPN":"特異事項が発生したら、すぐさまご報告いたします。","ENG":"If anything comes up, I will report to you immediately.","TWN":"有什麼特殊情況，會再馬上向您報告。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 어디 해보자고. 최고 관리자.","JPN":"いいぞ。やってみようじゃないか。最高管理者。","ENG":"All right. Let's see, Supreme Administrator.","TWN":"很好，那就試試看吧，最高管理者。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"누가 먼저 답을 찾을지 말이야.","JPN":"どちらが先に答えを見つけることができるか。","ENG":"It's a race to see who finds the answer first.","TWN":"看看誰能先找到答案。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};